14	
15	//! HTML clipboard parsing — extracts typed spans with labels and positions.
16	
17	use scraper::{ElementRef, Html, Node};
18	
19	// ---------------------------------------------------------------------------
20	// Public types
21	// ---------------------------------------------------------------------------
22	
23	#[derive(Debug, Clone, PartialEq, Eq)]
24	pub enum apcrp_SpanKind {
25	    LabeledField,
26	    SectionHeader,
27	    Narrative,
28	}
29	
30	/// A typed span extracted from Epic HTML.
31	///
32	/// `offset` is the start position of this span's contribution in the
33	/// plain-text output.  For position mapping: a character at position P in
34	/// `plain_text` belongs to the span whose `offset` is the largest value ≤ P.
35	#[derive(Debug, Clone)]
36	pub struct apcrp_Span {
37	    pub kind:   apcrp_SpanKind,
38	    pub label:  Option<String>,
39	    pub text:   String,
40	    pub offset: usize,
41	}
42	
43	/// Parsed Epic HTML document — typed spans plus derived plain text.
44	#[derive(Debug)]
45	pub struct apcrp_Document {
46	    pub spans:      Vec<apcrp_Span>,
47	    pub plain_text: String,
48	}
49	
50	// ---------------------------------------------------------------------------
51	// Constants
52	// ---------------------------------------------------------------------------
53	
54	/// Known Epic section header prefixes.  Matching uses `starts_with` so that
55	/// suffixes like "(Home)" or "(04/08/2026 06:00)" pass through.
56	pub(crate) const ZAPCRP_SECTION_PREFIXES: &[&str] = &[
57	    "Assessment/Plan",
58	    "Allergies",
59	    "Chief Complaint",
60	    "Cognitive Assessment",
61	    "Family History",
62	    "History of Present Illness",
63	    "Imaging",
64	    "Laboratory Results",
65	    "Medications",
66	    "Past Medical History",
67	    "Physical Exam",
68	    "Reason for Consult",
69	    "Review of Systems",
70	    "Social History",
71	    "Vitals",
72	];
73	
74	// ---------------------------------------------------------------------------
75	// Public API
76	// ---------------------------------------------------------------------------
77	
78	pub fn apcrp_parse(html: &str) -> apcrp_Document {
79	    let tree = Html::parse_document(html);
80	    let root = tree.root_element();
81	    let mut tokens = Vec::new();
82	    zapcrp_tokenize_element(root, &mut tokens);
83	    zapcrp_build_document(&tokens)
84	}
85	
86	// ---------------------------------------------------------------------------
87	// Internal — tokenizer
88	// ---------------------------------------------------------------------------
89	
90	#[derive(Debug)]
91	pub(crate) enum zapcrp_Token {
92	    Bold(String),
93	    Text(String),
94	    LineBreak,
95	    BlockStart,
96	    BlockEnd,
97	}
98	
99	fn zapcrp_tokenize_element(elem: ElementRef, tokens: &mut Vec<zapcrp_Token>) {
100	    let tag = elem.value().name.local.as_ref();
101	    match tag {
102	        "b" | "strong" => {
103	            let text: String = elem.text().collect();
104	            if !text.is_empty() {
105	                tokens.push(zapcrp_Token::Bold(text));
106	            }
107	        }
108	        "br" => {
109	            tokens.push(zapcrp_Token::LineBreak);
110	        }
111	        "div" | "table" => {
112	            tokens.push(zapcrp_Token::BlockStart);
113	            zapcrp_visit_children(elem, tokens);
114	            tokens.push(zapcrp_Token::BlockEnd);
115	        }
116	        "tr" => {
117	            zapcrp_visit_children(elem, tokens);
118	            tokens.push(zapcrp_Token::LineBreak);
119	        }
120	        _ => {
121	            zapcrp_visit_children(elem, tokens);
122	        }
123	    }
124	}
125	
126	fn zapcrp_visit_children(elem: ElementRef, tokens: &mut Vec<zapcrp_Token>) {
127	    for child in elem.children() {
128	        match child.value() {
129	            Node::Text(t) => {
130	                let s: &str = t;
131	                if !s.is_empty() {
132	                    tokens.push(zapcrp_Token::Text(s.to_string()));
133	                }
134	            }
135	            Node::Element(_) => {
136	                if let Some(child_elem) = ElementRef::wrap(child) {
137	                    zapcrp_tokenize_element(child_elem, tokens);
138	                }
139	            }
140	            _ => {}
141	        }
142	    }
143	}
144	
145	// ---------------------------------------------------------------------------
146	// Internal — span builder
147	// ---------------------------------------------------------------------------
148	
149	pub(crate) fn zapcrp_is_section_header(label: &str) -> bool {
150	    ZAPCRP_SECTION_PREFIXES
151	        .iter()
152	        .any(|&prefix| label.starts_with(prefix))
153	}
154	
155	fn zapcrp_build_document(tokens: &[zapcrp_Token]) -> apcrp_Document {
156	    let mut spans = Vec::new();
157	    let mut plain_text = String::new();
158	    let mut narrative_buf = String::new();
159	    let mut narrative_offset: usize = 0;
160	    let mut i = 0;
161	
162	    while i < tokens.len() {
163	        match &tokens[i] {
164	            zapcrp_Token::Bold(raw) if zapcrp_is_bold_label(raw) => {
165	                zapcrp_flush_narrative(
166	                    &mut narrative_buf,
167	                    narrative_offset,
168	                    &mut spans,
169	                    &mut plain_text,
170	                );
171	
172	                let label = raw.trim_end().trim_end_matches(':').trim().to_string();
173	
174	                if zapcrp_is_section_header(&label) {
175	                    let offset = plain_text.len();
176	                    plain_text.push_str(&label);
177	                    plain_text.push_str(":\n");
178	                    spans.push(apcrp_Span {
179	                        kind:   apcrp_SpanKind::SectionHeader,
180	                        label:  Some(label),
181	                        text:   String::new(),
182	                        offset,
183	                    });
184	                    i += 1;
185	                    if i < tokens.len() && matches!(&tokens[i], zapcrp_Token::LineBreak) {
186	                        i += 1;
187	                    }
188	                    narrative_offset = plain_text.len();
189	                    continue;
190	                }
191	
192	                // Labeled field — collect value until next boundary.
193	                let offset = plain_text.len();
194	                let mut value_parts: Vec<String> = Vec::new();
195	                i += 1;
196	                while i < tokens.len() {
197	                    match &tokens[i] {
198	                        zapcrp_Token::Bold(t) if zapcrp_is_bold_label(t) => break,
199	                        zapcrp_Token::LineBreak
200	                        | zapcrp_Token::BlockStart
201	                        | zapcrp_Token::BlockEnd => {
202	                            i += 1;
203	                            break;
204	                        }
205	                        zapcrp_Token::Text(t) => value_parts.push(t.clone()),
206	                        zapcrp_Token::Bold(t) => value_parts.push(t.clone()),
207	                    }
208	                    i += 1;
209	                }
210	                let value = zapcrp_join_inline(&value_parts);
211	                plain_text.push_str(&label);
212	                plain_text.push_str(": ");
213	                plain_text.push_str(&value);
214	                plain_text.push('\n');
215	                spans.push(apcrp_Span {
216	                    kind:   apcrp_SpanKind::LabeledField,
217	                    label:  Some(label),
218	                    text:   value,
219	                    offset,
220	                });
221	                narrative_offset = plain_text.len();
222	                continue;
223	            }
224	
225	            zapcrp_Token::Bold(text) => {
226	                zapcrp_append_narrative(&mut narrative_buf, &mut narrative_offset, &plain_text, text);
227	            }
228	            zapcrp_Token::Text(text) => {
229	                zapcrp_append_narrative(&mut narrative_buf, &mut narrative_offset, &plain_text, text);
230	            }
231	            zapcrp_Token::LineBreak => {
232	                if !narrative_buf.is_empty() {
233	                    narrative_buf.push('\n');
234	                }
235	            }
236	            zapcrp_Token::BlockStart | zapcrp_Token::BlockEnd => {
237	                zapcrp_flush_narrative(
238	                    &mut narrative_buf,
239	                    narrative_offset,
240	                    &mut spans,
241	                    &mut plain_text,
242	                );
243	                narrative_offset = plain_text.len();
244	            }
245	        }
246	        i += 1;
247	    }
248	
249	    zapcrp_flush_narrative(&mut narrative_buf, narrative_offset, &mut spans, &mut plain_text);
250	
251	    apcrp_Document { spans, plain_text }
252	}
253	
254	/// True when a Bold token looks like a label: trimmed text ends with ':'.
255	fn zapcrp_is_bold_label(raw: &str) -> bool {
256	    raw.trim_end().ends_with(':')
257	}
258	
259	/// Append raw text to the narrative buffer, recording the start offset on
260	/// first non-empty append.
261	fn zapcrp_append_narrative(
262	    buf: &mut String,
263	    offset: &mut usize,
264	    plain_text: &str,
265	    raw: &str,
266	) {
267	    if buf.is_empty() {
268	        *offset = plain_text.len();
269	    }
270	    buf.push_str(raw);
271	}
272	
273	/// Flush the narrative buffer into a Narrative span.
274	fn zapcrp_flush_narrative(
275	    buf: &mut String,
276	    offset: usize,
277	    spans: &mut Vec<apcrp_Span>,
278	    plain_text: &mut String,
279	) {
280	    if buf.is_empty() {
281	        return;
282	    }
283	    let normalized = zapcrp_normalize_whitespace(buf);
284	    if !normalized.is_empty() {
285	        plain_text.push_str(&normalized);
286	        plain_text.push('\n');
287	        spans.push(apcrp_Span {
288	            kind:   apcrp_SpanKind::Narrative,
289	            label:  None,
290	            text:   normalized,
291	            offset,
292	        });
293	    }
294	    buf.clear();
295	}
296	
297	/// Join inline text fragments: concatenate then collapse whitespace.
298	fn zapcrp_join_inline(parts: &[String]) -> String {
299	    let raw: String = parts.concat();
300	    zapcrp_normalize_whitespace(&raw)
301	}
302	
303	/// Normalize whitespace: preserve paragraph breaks (`\n\n`), collapse single
304	/// newlines and runs of spaces to a single space, trim.
305	fn zapcrp_normalize_whitespace(s: &str) -> String {
306	    let paragraphs: Vec<&str> = s.split("\n\n").collect();
307	    let normalized: Vec<String> = paragraphs
308	        .iter()
309	        .map(|p| {
310	            p.split_whitespace()
311	                .collect::<Vec<_>>()
312	                .join(" ")
313	        })
314	        .filter(|p| !p.is_empty())
315	        .collect();
316	    normalized.join("\n\n")
317	}
