15	//! Dictionary loading — surname, firstname, city blacklists and medical/english whitelists.
16	
17	use aho_corasick::{AhoCorasick, MatchKind};
18	use std::collections::HashSet;
19	
20	// ---------------------------------------------------------------------------
21	// Public types
22	// ---------------------------------------------------------------------------
23	
24	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
25	pub enum apcrd_WordClass {
26	    Blacklisted,
27	    Whitelisted,
28	    Collision,
29	    Neutral,
30	}
31	
32	pub struct apcrd_Dictionaries {
33	    automaton:     AhoCorasick,
34	    blacklist_set: HashSet<String>,
35	    whitelist:     HashSet<String>,
36	}
37	
38	// ---------------------------------------------------------------------------
39	// Constants — embedded dictionary data
40	// ---------------------------------------------------------------------------
41	
42	const ZAPCRD_SURNAMES:          &str = include_str!("../dictionaries/surnames.txt");
43	const ZAPCRD_FIRSTNAMES:        &str = include_str!("../dictionaries/firstnames.txt");
44	const ZAPCRD_CITIES:            &str = include_str!("../dictionaries/cities.txt");
45	const ZAPCRD_MEDICAL_WHITELIST: &str = include_str!("../dictionaries/medical_whitelist.txt");
46	const ZAPCRD_ENGLISH_WHITELIST: &str = include_str!("../dictionaries/english_whitelist.txt");
47	
48	// ---------------------------------------------------------------------------
49	// Public API
50	// ---------------------------------------------------------------------------
51	
52	impl apcrd_Dictionaries {
53	    pub fn apcrd_load() -> Self {
54	        let surnames   = zapcrd_load_lines(ZAPCRD_SURNAMES);
55	        let firstnames = zapcrd_load_lines(ZAPCRD_FIRSTNAMES);
56	        let cities     = zapcrd_load_lines(ZAPCRD_CITIES);
57	
58	        let mut all_entries = Vec::new();
59	        all_entries.extend(surnames);
60	        all_entries.extend(firstnames);
61	        all_entries.extend(cities);
62	
63	        let blacklist_set: HashSet<String> = all_entries.into_iter().collect();
64	        let blacklist_vec: Vec<String> = blacklist_set.iter().cloned().collect();
65	
66	        let automaton = AhoCorasick::builder()
67	            .match_kind(MatchKind::LeftmostLongest)
68	            .build(&blacklist_vec)
69	            .expect("aho-corasick build failed");
70	
71	        let medical = zapcrd_load_lines(ZAPCRD_MEDICAL_WHITELIST);
72	        let english = zapcrd_load_lines(ZAPCRD_ENGLISH_WHITELIST);
73	        let mut whitelist = HashSet::new();
74	        whitelist.extend(medical);
75	        whitelist.extend(english);
76	
77	        Self { automaton, blacklist_set, whitelist }
78	    }
79	
80	    pub fn apcrd_is_blacklisted(&self, word: &str) -> bool {
81	        self.blacklist_set.contains(&word.to_lowercase())
82	    }
83	
84	    pub fn apcrd_is_whitelisted(&self, word: &str) -> bool {
85	        self.whitelist.contains(&word.to_lowercase())
86	    }
87	
88	    pub fn apcrd_classify_word(&self, word: &str) -> apcrd_WordClass {
89	        let black = self.apcrd_is_blacklisted(word);
90	        let white = self.apcrd_is_whitelisted(word);
91	        match (black, white) {
92	            (true, true)   => apcrd_WordClass::Collision,
93	            (true, false)  => apcrd_WordClass::Blacklisted,
94	            (false, true)  => apcrd_WordClass::Whitelisted,
95	            (false, false) => apcrd_WordClass::Neutral,
96	        }
97	    }
98	
99	    pub fn apcrd_automaton(&self) -> &AhoCorasick {
100	        &self.automaton
101	    }
102	}
103	
104	// ---------------------------------------------------------------------------
105	// Internal
106	// ---------------------------------------------------------------------------
107	
108	fn zapcrd_load_lines(text: &str) -> Vec<String> {
109	    text.lines()
110	        .map(|l| l.trim().to_lowercase())
111	        .filter(|l| !l.is_empty())
112	        .collect()
113	}
